queries.sparql:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?meeting_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasMeetings ?child ; p:hasHoa_Boards ?parent . } GROUP BY ?child }
  ?child p:meeting_type ?meeting_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hoa_Boards } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?meeting_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasMeetings ?child ; p:hasHoa_Boards ?parent . } GROUP BY ?child }
  ?child p:meeting_type ?meeting_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hoa_Boards } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?address ?meeting_type WHERE {
  ?hoa_boards_meetings a :Hoa_Boards_Meetings .
  ?meetings a :Meetings .
  ?hoa_boards_meetings p:hasMeetings ?meetings .
  ?hoa_boards a :Hoa_Boards .
  ?hoa_boards_meetings p:hasHoa_Boards ?hoa_boards .
  ?hoa_boards p:address ?address .
  ?meetings p:meeting_type ?meeting_type .
} }
}
